  1→import {
  2→	BadRequestException,
  3→	Injectable,
  4→	Logger,
  5→	NotFoundException,
  6→} from '@nestjs/common';
  7→
  8→import { AlgoliaService } from '@modules/algolia/algolia.service';
  9→import { ColorMatchWorkerService } from '@modules/color-match-worker/color-match-worker.service';
 10→import { StyleAlternativesService } from '@modules/db/style-alternatives/style-alternatives.service';
 11→import { StyleColorsService } from '@modules/db/style-colors/style-colors.service';
 12→import { IStyleColorBase } from '@modules/db/style-colors/types/style-color.base.interface';
 13→import { StylesService } from '@modules/db/styles/styles.service';
 14→import { IStylesMvBase } from '@modules/db/styles-mv/types/styles-mv.base.interface';
 15→import { MetricsService } from '@modules/metrics/metrics.service';
 16→import { ProductHydrationService } from '@modules/product-hydration/product-hydration.service';
 17→
 18→import { sortStyles } from '@utils/sort-styles.utils';
 19→
 20→import { dailyTrackingKeys } from '@constants/common.constant';
 21→
 22→import { IRelatedProduct } from '@interfaces/related-product.interface';
 23→
 24→import { LogExecution } from '@decorators/log-execution.decorator';
 25→
 26→import { BrandProductsQueryDto } from '@dto/brand-products/brand-products-query.dto';
 27→import { BrandProductsResponseDto } from '@dto/brand-products/brand-products-response.dto';
 28→import { RelatedProductsQueryDto } from '@dto/related-products/related-products-query.dto';
 29→import { RelatedProductsResponseDto } from '@dto/related-products/related-products-response.dto';
 30→
 31→@Injectable()
 32→export class RelatedProductsService {
 33→	private readonly logger = new Logger(RelatedProductsService.name);
 34→
 35→	constructor(
 36→		private readonly algoliaService: AlgoliaService,
 37→		private readonly colorMatchWorkerService: ColorMatchWorkerService,
 38→		private readonly styleAlternativesService: StyleAlternativesService,
 39→		private readonly metricsService: MetricsService,
 40→		private readonly productHydrationService: ProductHydrationService,
 41→		private readonly styleColorsService: StyleColorsService,
 42→		private readonly stylesService: StylesService,
 43→	) {}
 44→
 45→	private async getCurrentColorStyle(
 46→		styleId: number,
 47→		colorId?: number,
 48→	): Promise<IStyleColorBase | null> {
 49→		if (colorId) {
 50→			const styleByColor = await this.styleColorsService.getStyleByStyleAndColorId({
 51→				styleId,
 52→				colorId,
 53→			});
 54→			if (styleByColor) {
 55→				return styleByColor;
 56→			}
 57→		}
 58→
 59→		const style = await this.styleColorsService.getStyleByStyleId({ styleId });
 60→		if (!style) {
 61→			this.logger.warn('No style found', { styleId });
 62→		}
 63→		return style;
 64→	}
 65→
 66→	private async applyColorMatching(
 67→		products: IRelatedProduct[],
 68→		mvRecords: Map<number, IStylesMvBase>,
 69→		currentStyleColor: IStyleColorBase,
 70→	): Promise<IRelatedProduct[]> {
 71→		const colorCache = new Map<
 72→			number,
 73→			ReturnType<typeof this.productHydrationService.convertMvColorsToProductColors>
 74→		>();
 75→
 76→		return Promise.all(
 77→			products.map(async (product) => {
 78→				const mv = mvRecords.get(product.style_id);
 79→				let colors = colorCache.get(product.style_id);
 80→				if (!colors) {
 81→					colors = this.productHydrationService.convertMvColorsToProductColors({
 82→						colors: mv?.colors ?? null,
 83→					});
 84→					colorCache.set(product.style_id, colors);
 85→				}
 86→				if (colors.length > 0) {
 87→					const closestColorId = await this.colorMatchWorkerService.findClosestColorId({
 88→						color: currentStyleColor,
 89→						palette: colors,
 90→					});
 91→					const closestColor = colors.find((c) => c.id === closestColorId);
 92→					if (closestColor) {
 93→						return {
 94→							...product,
 95→							color: closestColorId,
 96→							image_src: closestColor.image_url ?? product.image_src,
 97→						};
 98→					}
 99→				}
100→				return product;
101→			}),
102→		);
103→	}
104→
105→	@LogExecution({
106→		paramFormatter: ([productId, query]: [string, RelatedProductsQueryDto]) => ({
107→			productId,
108→			colorId: query.colorId,
109→			limit: query.limit,
110→		}),
111→		responseFormatter: /* istanbul ignore next */ (res: RelatedProductsResponseDto) => ({
112→			count: res?.related_products?.length ?? 0,
113→			mmsFallback: res?.mms_fallback ?? false,
114→		}),
115→	})
116→	async getRelatedProducts(
117→		productId: string,
118→		query: RelatedProductsQueryDto,
119→	): Promise<RelatedProductsResponseDto> {
120→		if (!productId || productId.trim() === '') {
121→			this.logger.error('Product ID is required to fetch related products');
122→			throw new BadRequestException('Product ID is required');
123→		}
124→
125→		const numericProductId = Number(productId);
126→		if (!Number.isInteger(numericProductId) || numericProductId <= 0) {
127→			this.logger.error(`Invalid Product ID format: ${productId}`);
128→			throw new BadRequestException(
129→				`Product ID must be a valid positive integer, received: ${productId}`,
130→			);
131→		}
132→
133→		const { limit, colorId } = query;
134→
135→		try {
136→			const styleIds = await this.algoliaService.getRelatedProductIds({
137→				productId: numericProductId,
138→			});
139→			this.logger.log('[getRelatedProducts] Algolia returned related IDs', {
140→				count: styleIds.length,
141→			});
142→
143→			if (styleIds.length === 0) {
144→				throw new NotFoundException(
145→					`No related products found for product ID: ${productId}`,
146→				);
147→			}
148→
149→			const [currentStyleColor, { products, mvRecords }] = await Promise.all([
150→				this.getCurrentColorStyle(numericProductId, colorId),
151→				this.productHydrationService.hydrateProductsWithColors({
152→					styleIds,
153→				}),
154→			]);
155→
156→			const relatedProducts = currentStyleColor
157→				? await this.applyColorMatching(products, mvRecords, currentStyleColor)
158→				: products;
159→			this.logger.log('[getRelatedProducts] Hydration complete', {
160→				hydratedCount: relatedProducts.length,
161→			});
162→
163→			if (relatedProducts.length === 0) {
164→				throw new NotFoundException(
165→					`No related products found for product ID: ${productId}`,
166→				);
167→			}
168→
169→			return {
170→				product_id: productId,
171→				related_products: relatedProducts.slice(0, limit),
172→				color_id: colorId ?? null,
173→			};
174→		} catch (error: unknown) {
175→			const err = error instanceof Error ? error : new Error(String(error));
176→			this.logger.error(
177→				`Error fetching related products from Algolia for productId ${productId}, colorId ${colorId}: ${err.message}`,
178→				err.stack,
179→			);
180→
181→			await this.metricsService.incrementDailyCounter({
182→				metricType: dailyTrackingKeys.MMS_REQUESTS,
183→			});
184→
185→			const [alternativeStyleIds, currentStyleColor] = await Promise.all([
186→				this.styleAlternativesService.getAlternativeStyleIds({
187→					styleId: numericProductId,
188→				}),
189→				this.getCurrentColorStyle(numericProductId, colorId),
190→			]);
191→			this.logger.log('[getRelatedProducts] DB alternatives fetched', {
192→				count: alternativeStyleIds.length,
193→			});
194→
195→			if (alternativeStyleIds.length === 0) {
196→				this.logger.warn(`No DB alternatives found for product ID: ${productId}`);
197→				return {
198→					product_id: productId,
199→					related_products: [],
200→					mms_fallback: true,
201→					color_id: colorId ?? null,
202→				};
203→			}
204→
205→			const alternatives = await this.productHydrationService.hydrateProducts({
206→				styleIds: alternativeStyleIds,
207→				currentStyleColor,
208→				activeOnly: true,
209→			});
210→
211→			this.logger.log('[getRelatedProducts] Fallback completed', {
212→				productId,
213→				fallbackCount: Math.min(alternatives.length, limit ?? alternatives.length),
214→			});
215→
216→			return {
217→				product_id: productId,
218→				related_products: alternatives.slice(0, limit),
219→				mms_fallback: true,
220→				color_id: colorId ?? null,
221→			};
222→		}
223→	}
224→
225→	@LogExecution({
226→		paramFormatter: ([query]: [BrandProductsQueryDto]) => ({
227→			brand: query.brand,
228→			styleId: query.styleId,
229→			colorId: query.colorId,
230→			limit: query.limit,
231→			sortBy: query.sortBy,
232→		}),
233→		responseFormatter: /* istanbul ignore next */ (res: BrandProductsResponseDto) => ({
234→			count: res?.brand_products?.length ?? 0,
235→		}),
236→	})
237→	async getBrandProducts(
238→		query: BrandProductsQueryDto,
239→	): Promise<BrandProductsResponseDto> {
240→		const { brand, limit, colorId, styleId, sortBy } = query;
241→
242→		this.logger.log('[getBrandProducts] Starting brand products fetch', {
243→			brand,
244→			styleId,
245→			colorId,
246→			sortBy,
247→			limit,
248→		});
249→
250→		try {
251→			const shouldFetchColor = Boolean(colorId && styleId);
252→
253→			const productLimit = limit ?? 30;
254→
255→			const [{ products, mvRecords }, currentStyleColor] = await Promise.all([
256→				this.productHydrationService.getProductsByBrands({
257→					brands: [brand],
258→					limit: productLimit,
259→				}),
260→				shouldFetchColor
261→					? this.styleColorsService.getStyleByStyleAndColorId({
262→							styleId: Number(styleId),
263→							colorId: Number(colorId),
264→						})
265→					: Promise.resolve(null),
266→			]);
267→			this.logger.log('[getBrandProducts] Brand products fetched', {
268→				count: products.length,
269→			});
270→
271→			if (products.length === 0) {
272→				throw new NotFoundException(`No products found for brand: ${brand}`);
273→			}
274→
275→			const productsWithColor = currentStyleColor
276→				? await (async () => {
277→						const colorCache = new Map<
278→							number,
279→							ReturnType<
280→								typeof this.productHydrationService.convertMvColorsToProductColors
281→							>
282→						>();
283→						return Promise.all(
284→							products.map(async (product) => {
285→								const mv = mvRecords.get(product.style_id);
286→								let colors = colorCache.get(product.style_id);
287→								if (!colors) {
288→									colors = this.productHydrationService.convertMvColorsToProductColors({
289→										colors: mv?.colors ?? null,
290→									});
291→									colorCache.set(product.style_id, colors);
292→								}
293→								if (colors.length > 0 && currentStyleColor) {
294→									const closestColorId =
295→										await this.colorMatchWorkerService.findClosestColorId({
296→											color: currentStyleColor,
297→											palette: colors,
298→										});
299→									const closestColor = colors.find((c) => c.id === closestColorId);
300→									if (closestColor) {
301→										return {
302→											...product,
303→											color: closestColorId,
304→											image_src: closestColor.image_url ?? product.image_src,
305→										};
306→									}
307→								}
308→								return product;
309→							}),
310→						);
311→					})()
312→				: products;
313→
314→			let finalProducts = productsWithColor;
315→
316→			if (sortBy) {
317→				this.logger.log('[getBrandProducts] Applying sort', { sortBy });
318→				let currentStyleCategoryId: number | null = null;
319→				if (sortBy === 'category' && styleId) {
320→					const currentStyle = await this.stylesService.getStyleById({
321→						styleId: Number(styleId),
322→					});
323→					currentStyleCategoryId = currentStyle?.primary_category_id ?? null;
324→				}
325→				finalProducts = sortStyles({
326→					products: productsWithColor,
327→					sortBy,
328→					currentStyleCategoryId,
329→				});
330→			}
331→
332→			return {
333→				product_id: styleId?.toString() ?? '',
334→				brand_products: finalProducts.slice(0, limit),
335→				color_id: colorId ?? null,
336→				brand,
337→				sort_by: sortBy ?? null,
338→			};
339→		} catch (error: unknown) {
340→			const err = error instanceof Error ? error : new Error(String(error));
341→			this.logger.error(
342→				`Failed to get products for brand ${query.brand}, styleId ${query.styleId}: ${err.message}`,
343→				err.stack,
344→			);
345→
346→			throw err;
347→		}
348→	}
349→}
