  1→import { BadRequestException, Injectable, Logger } from '@nestjs/common';
  2→
  3→import { CategoryCorrelationsService } from '@modules/db/category-correlations/category-correlations.service';
  4→import { RootCategoriesCorrelationsService } from '@modules/db/root-categories-correlations/root-categories-correlations.service';
  5→import { StyleColorsService } from '@modules/db/style-colors/style-colors.service';
  6→import { IStyleColorBase } from '@modules/db/style-colors/types/style-color.base.interface';
  7→import { StyleCopurchasesService } from '@modules/db/style-copurchases/style-copurchases.service';
  8→import { StylesService } from '@modules/db/styles/styles.service';
  9→import { IStyleBase } from '@modules/db/styles/types/style.base.interface';
 10→import { StylesMvService } from '@modules/db/styles-mv/styles-mv.service';
 11→import { ProductHydrationService } from '@modules/product-hydration/product-hydration.service';
 12→
 13→import { IRelatedProduct } from '@interfaces/related-product.interface';
 14→
 15→import { LogExecution } from '@decorators/log-execution.decorator';
 16→
 17→import { FrequentlyBoughtTogetherQueryDto } from '@dto/frequently-bought-together/frequently-bought-together-query.dto';
 18→import { FrequentlyBoughtTogetherResponseDto } from '@dto/frequently-bought-together/frequently-bought-together-response.dto';
 19→import { FrequentlyBoughtTogetherRootCategoriesQueryDto } from '@dto/frequently-bought-together/frequently-bought-together-root-categories-query.dto';
 20→import { FrequentlyBoughtTogetherRootCategoriesResponseDto } from '@dto/frequently-bought-together/frequently-bought-together-root-categories-response.dto';
 21→import { FrequentlyBoughtTogetherV2QueryDto } from '@dto/frequently-bought-together/frequently-bought-together-v2-query.dto';
 22→import { FrequentlyBoughtTogetherV2ResponseDto } from '@dto/frequently-bought-together/frequently-bought-together-v2-response.dto';
 23→
 24→@Injectable()
 25→export class FrequentlyBoughtTogetherService {
 26→	private readonly logger = new Logger(FrequentlyBoughtTogetherService.name);
 27→
 28→	constructor(
 29→		private readonly stylesService: StylesService,
 30→		private readonly styleColorsService: StyleColorsService,
 31→		private readonly categoryCorrelationsService: CategoryCorrelationsService,
 32→		private readonly rootCategoriesCorrelationsService: RootCategoriesCorrelationsService,
 33→		private readonly productHydrationService: ProductHydrationService,
 34→		private readonly styleCopurchasesService: StyleCopurchasesService,
 35→		private readonly stylesMvService: StylesMvService,
 36→	) {}
 37→
 38→	private async getCurrentColorStyle(styleId?: number): Promise<IStyleColorBase | null> {
 39→		if (!styleId) {
 40→			return null;
 41→		}
 42→
 43→		const currentStyle = await this.styleColorsService.getStyleByStyleId({
 44→			styleId: Number(styleId),
 45→		});
 46→
 47→		if (!currentStyle) {
 48→			this.logger.warn('No style found', { styleId });
 49→		}
 50→
 51→		return currentStyle;
 52→	}
 53→
 54→	@LogExecution({
 55→		paramFormatter: ([query]: [FrequentlyBoughtTogetherQueryDto]) => ({
 56→			styleIds: query.styleIds,
 57→			styleIdsCount: query.styleIds.length,
 58→			excludeCount: query.exclude?.length ?? 0,
 59→		}),
 60→		responseFormatter: /* istanbul ignore next */ (
 61→			res: FrequentlyBoughtTogetherResponseDto,
 62→		) => ({
 63→			count: res?.frequently_bought_together?.length ?? 0,
 64→			fallbackUsed: res?.fallback_used ?? false,
 65→		}),
 66→	})
 67→	async getFrequentlyBoughtTogether(
 68→		query: FrequentlyBoughtTogetherQueryDto,
 69→	): Promise<FrequentlyBoughtTogetherResponseDto> {
 70→		const { styleIds, exclude = [] } = query;
 71→		let fallbackUsed = false;
 72→
 73→		this.logger.log('[getFrequentlyBoughtTogether] Starting FBT fetch', {
 74→			styleIds,
 75→			excludeCount: exclude.length,
 76→		});
 77→
 78→		try {
 79→			const styles = await Promise.all(
 80→				styleIds.map((id) => this.stylesService.getStyleById({ styleId: id })),
 81→			);
 82→
 83→			const validStyles = styles.filter(Boolean) as IStyleBase[];
 84→			if (validStyles.length === 0) {
 85→				throw new BadRequestException(
 86→					`No styles found for styleIds: ${styleIds.join(', ')}`,
 87→				);
 88→			}
 89→
 90→			this.logger.log('[getFrequentlyBoughtTogether] Valid styles found', {
 91→				validCount: validStyles.length,
 92→				inputCount: styleIds.length,
 93→			});
 94→
 95→			const cartCategoryIds = validStyles
 96→				.map((_style) => _style.primary_category_id)
 97→				.filter((id): id is number => id !== null && id !== undefined);
 98→			let correlatedCategoryIds: number[] = [];
 99→
100→			for (const style of validStyles) {
101→				if (style.primary_category_id) {
102→					const correlations =
103→						await this.categoryCorrelationsService.getTopCorrelatedCategories({
104→							primaryCategoryId: style.primary_category_id,
105→							limit: 4,
106→							exclude: cartCategoryIds,
107→						});
108→
109→					correlatedCategoryIds.push(...correlations.map((corr) => corr.edge_id));
110→				}
111→			}
112→
113→			correlatedCategoryIds = [...new Set(correlatedCategoryIds)];
114→			this.logger.debug('Found correlated categories', {
115→				count: correlatedCategoryIds.length,
116→				styleIds,
117→			});
118→
119→			if (correlatedCategoryIds.length === 0) {
120→				this.logger.warn('No correlations found, using fallback', { styleIds });
121→				correlatedCategoryIds = await this.stylesService.getMostPopularCategories({
122→					limit: 4,
123→				});
124→				fallbackUsed = true;
125→			}
126→
127→			this.logger.log(
128→				'[getFrequentlyBoughtTogether] Fetching popular styles from correlated categories',
129→				{
130→					correlatedCategoryIds,
131→				},
132→			);
133→			const allPopularStyles = await this.stylesService.getMostPopularStylesByCategories({
134→				categoryIds: correlatedCategoryIds,
135→				limit: 5,
136→				excludeIds: [...styleIds, ...exclude],
137→			});
138→			const allPopularStylesIds = allPopularStyles.map((_style) => _style.style_id);
139→			this.logger.log('[getFrequentlyBoughtTogether] Popular styles fetched', {
140→				count: allPopularStylesIds.length,
141→			});
142→
143→			const currentStyleColor = await this.getCurrentColorStyle(styleIds[0]);
144→			const products = await this.productHydrationService.hydrateProducts({
145→				styleIds: allPopularStylesIds,
146→				currentStyleColor,
147→			});
148→			this.logger.log('[getFrequentlyBoughtTogether] Products hydrated', {
149→				hydratedCount: products.length,
150→			});
151→
152→			const productsByStyleId = new Map(products.map((p) => [p.style_id, p]));
153→			const activeStyleIds = new Set(products.map((p) => p.style_id));
154→
155→			const filteredAllPopularStyles = allPopularStyles.filter((s) =>
156→				activeStyleIds.has(s.style_id),
157→			);
158→
159→			const stylesWithCategory = filteredAllPopularStyles.filter(
160→				(style): style is IStyleBase & { primary_category_id: number } =>
161→					style.primary_category_id !== null,
162→			);
163→			const selectedStyleIds = this.selectRandomStylesFromCategories(
164→				stylesWithCategory,
165→				correlatedCategoryIds,
166→			);
167→
168→			const selectedStyles = allPopularStyles.filter((style) =>
169→				selectedStyleIds.includes(style.style_id),
170→			);
171→			const sortedStyles = selectedStyles
172→				.sort((a, b) => b.purchases_count - a.purchases_count)
173→				.slice(0, 4);
174→			const finalStyleIds = sortedStyles.map((style) => style.style_id);
175→
176→			let finalProducts = finalStyleIds
177→				.map((id) => productsByStyleId.get(id))
178→				.filter((p): p is IRelatedProduct => p !== undefined);
179→
180→			if (finalStyleIds.length < 4) {
181→				this.logger.debug('Using fallback for additional recommendations', {
182→					currentCount: finalStyleIds.length,
183→					targetCount: 4,
184→				});
185→
186→				const regularResult = await this.getFrequentlyBoughtTogetherByRootCategories({
187→					styleIds,
188→					exclude: finalStyleIds.concat(exclude),
189→				});
190→
191→				const additionalProducts = regularResult.frequently_bought_together
192→					.filter((product) => !finalStyleIds.includes(product.style_id))
193→					.slice(0, 4 - finalStyleIds.length);
194→
195→				finalProducts = finalProducts.concat(additionalProducts);
196→
197→				this.logger.debug('Added additional recommendations', {
198→					count: additionalProducts.length,
199→				});
200→			}
201→
202→			this.logger.debug('Selected styles for recommendations', {
203→				count: finalProducts.length,
204→			});
205→
206→			return {
207→				style_ids: styleIds,
208→				frequently_bought_together: finalProducts,
209→				fallback_used: fallbackUsed,
210→			};
211→		} catch (error) {
212→			this.logger.error(
213→				`Error getting frequently bought together for styles ${styleIds.join(', ')}: ${(error as Error).message}`,
214→				(error as Error).stack,
215→			);
216→			throw error;
217→		}
218→	}
219→
220→	private selectRandomStylesFromCategories(
221→		styles: { primary_category_id?: number; style_id: number }[],
222→		categoryIds: number[],
223→	): number[] {
224→		return this.selectRandomStylesFromCategoriesGeneric(
225→			styles,
226→			categoryIds,
227→			'primary_category_id',
228→			'Category',
229→		);
230→	}
231→
232→	private selectRandomStylesFromRootCategories(
233→		styles: { root_category_id?: number; style_id: number }[],
234→		categoryIds: number[],
235→	): number[] {
236→		return this.selectRandomStylesFromCategoriesGeneric(
237→			styles,
238→			categoryIds,
239→			'root_category_id',
240→			'Root category',
241→		);
242→	}
243→
244→	private selectRandomStylesFromCategoriesGeneric<
245→		T extends { style_id: number } & Partial<Record<K, number>>,
246→		K extends string,
247→	>(styles: T[], categoryIds: number[], categoryKey: K, categoryLabel: string): number[] {
248→		if (categoryIds.length === 0) {
249→			return [];
250→		}
251→
252→		const stylesByCategory: Record<number, T[]> = {};
