303→	async getFrequentlyBoughtTogetherByRootCategories(
304→		query: FrequentlyBoughtTogetherRootCategoriesQueryDto,
305→	): Promise<FrequentlyBoughtTogetherRootCategoriesResponseDto> {
306→		const { styleIds, exclude = [] } = query;
307→		let fallbackUsed = false;
308→
309→		this.logger.log(
310→			'[getFrequentlyBoughtTogetherByRootCategories] Starting root category FBT fetch',
311→			{
312→				styleIds,
313→				excludeCount: exclude.length,
314→			},
315→		);
316→
317→		try {
318→			const styles = await Promise.all(
319→				styleIds.map((id) => this.stylesService.getStyleById({ styleId: id })),
320→			);
321→
322→			const validStyles = styles.filter(Boolean) as IStyleBase[];
323→			if (validStyles.length === 0) {
324→				throw new BadRequestException(
325→					`No styles found for styleIds: ${styleIds.join(', ')}`,
326→				);
327→			}
328→
329→			const cartRootCategoryIds = validStyles
330→				.map((_style) => _style.root_category_id)
331→				.filter(Boolean) as number[];
332→			let correlatedCategoryIds: number[] = [];
333→
334→			for (const style of validStyles) {
335→				if (style.root_category_id) {
336→					const correlations =
337→						await this.rootCategoriesCorrelationsService.getTopCorrelatedCategories({
338→							rootCategoryId: style.root_category_id,
339→							limit: 4,
340→							exclude: cartRootCategoryIds,
341→						});
342→
343→					correlatedCategoryIds.push(...correlations.map((corr) => corr.edge_id));
344→				}
345→			}
346→
347→			correlatedCategoryIds = [...new Set(correlatedCategoryIds)];
348→			this.logger.debug('Found correlated root categories', {
349→				count: correlatedCategoryIds.length,
350→				styleIds,
351→			});
352→
353→			if (correlatedCategoryIds.length === 0) {
354→				this.logger.warn('No root category correlations found, using fallback', {
355→					styleIds,
356→				});
357→				correlatedCategoryIds = await this.stylesService.getMostPopularRootCategories({
358→					limit: 4,
359→				});
360→				fallbackUsed = true;
361→			}
362→
363→			const allPopularStyles =
364→				await this.stylesService.getMostPopularStylesByRootCategories({
365→					categoryIds: correlatedCategoryIds,
366→					limit: 5,
367→					excludeIds: [...styleIds, ...exclude],
368→				});
369→			const allPopularStylesIds = allPopularStyles.map((_style) => _style.style_id);
370→
371→			const currentStyleColor = await this.getCurrentColorStyle(styleIds[0]);
372→			const products = await this.productHydrationService.hydrateProducts({
373→				styleIds: allPopularStylesIds,
374→				currentStyleColor,
375→			});
376→
377→			const productsByStyleId = new Map(products.map((p) => [p.style_id, p]));
378→			const activeStyleIds = new Set(products.map((p) => p.style_id));
379→
380→			const filteredAllPopularStyles = allPopularStyles.filter((s) =>
381→				activeStyleIds.has(s.style_id),
382→			);
383→
384→			const selectedStyleIds = this.selectRandomStylesFromRootCategories(
385→				filteredAllPopularStyles,
386→				correlatedCategoryIds,
387→			);
388→
389→			const selectedStyles = allPopularStyles.filter((style) =>
390→				selectedStyleIds.includes(style.style_id),
391→			);
392→			const sortedStyles = selectedStyles
393→				.sort((a, b) => b.purchases_count - a.purchases_count)
394→				.slice(0, 4);
395→			const finalStyleIds = sortedStyles.map((style) => style.style_id);
396→
397→			if (finalStyleIds.length === 0) {
398→				this.logger.warn('No style IDs selected for root category recommendations', {
399→					styleIds,
400→				});
401→				return {
402→					style_ids: styleIds,
403→					frequently_bought_together: [],
404→					fallback_used: fallbackUsed,
405→				};
406→			}
407→
408→			this.logger.debug('Selected styles for root category recommendations', {
409→				count: finalStyleIds.length,
410→			});
411→
412→			const finalProducts = finalStyleIds
413→				.map((id) => productsByStyleId.get(id))
414→				.filter((p): p is IRelatedProduct => p !== undefined);
415→
416→			return {
417→				style_ids: styleIds,
418→				frequently_bought_together: finalProducts,
419→				fallback_used: fallbackUsed,
420→			};
421→		} catch (error) {
422→			this.logger.error(
423→				`Error getting frequently bought together by root categories for styles ${styleIds.join(', ')}: ${(error as Error).message}`,
424→				(error as Error).stack,
425→			);
426→			throw error;
427→		}
428→	}
