446→	async getFrequentlyBoughtTogetherV2(
447→		query: FrequentlyBoughtTogetherV2QueryDto,
448→	): Promise<FrequentlyBoughtTogetherV2ResponseDto> {
449→		const {
450→			styleId,
451→			colorId,
452→			exclude = [],
453→			limit = 4,
454→			diversifyCategories = false,
455→			favorOppositeType = false,
456→		} = query;
457→
458→		try {
459→			const style = await this.stylesService.getStyleById({ styleId });
460→			if (!style) {
461→				throw new BadRequestException(`No style found for styleId: ${styleId}`);
462→			}
463→
464→			const useDiversified = diversifyCategories || favorOppositeType;
465→			let copurchasedStyleIds: number[];
466→
467→			if (useDiversified) {
468→				let seedStyleType: string | null = null;
469→				if (favorOppositeType) {
470→					const mvStyle = await this.stylesMvService.getByStyleId({ styleId });
471→					seedStyleType = mvStyle?.style_type ?? null;
472→				}
473→
474→				const diversifiedCopurchases =
475→					await this.styleCopurchasesService.getTopCopurchasesDiversified({
476→						styleId,
477→						limit,
478→						excludeIds: [styleId, ...exclude],
479→						diversifyCategories,
480→						favorOppositeType,
481→						seedStyleType,
482→					});
483→
484→				if (diversifiedCopurchases.length === 0) {
485→					this.logger.debug('No diversified copurchases found, falling back to v1', {
486→						styleId,
487→					});
488→					const v1Result = await this.getFrequentlyBoughtTogether({
489→						styleIds: [styleId],
490→						exclude,
491→					});
492→
493→					return {
494→						style_id: styleId,
495→						frequently_bought_together: v1Result.frequently_bought_together.slice(
496→							0,
497→							limit,
498→						),
499→						fallback_used: true,
500→					};
501→				}
502→
503→				copurchasedStyleIds = diversifiedCopurchases.map((c) => c.paired_style_id);
504→			} else {
505→				const copurchases = await this.styleCopurchasesService.getTopCopurchases({
506→					styleId,
507→					limit,
508→					excludeIds: [styleId, ...exclude],
509→				});
510→
511→				if (copurchases.length === 0) {
512→					this.logger.debug('No copurchases found, falling back to v1', { styleId });
513→					const v1Result = await this.getFrequentlyBoughtTogether({
514→						styleIds: [styleId],
515→						exclude,
516→					});
517→
518→					return {
519→						style_id: styleId,
520→						frequently_bought_together: v1Result.frequently_bought_together.slice(
521→							0,
522→							limit,
523→						),
524→						fallback_used: true,
525→					};
526→				}
527→
528→				copurchasedStyleIds = copurchases.map((c) => c.paired_style_id);
529→			}
530→
531→			let currentStyleColor: IStyleColorBase | null = null;
532→			if (colorId) {
533→				currentStyleColor = await this.styleColorsService.getStyleByStyleAndColorId({
534→					styleId,
535→					colorId,
536→				});
537→			}
538→			currentStyleColor ??= await this.getCurrentColorStyle(styleId);
539→
540→			const products = await this.productHydrationService.hydrateProducts({
541→				styleIds: copurchasedStyleIds,
542→				currentStyleColor,
543→			});
544→
545→			this.logger.debug('FBT v2 results', {
546→				styleId,
547→				resultCount: products.length,
548→			});
549→
550→			return {
551→				style_id: styleId,
552→				frequently_bought_together: products,
553→				fallback_used: false,
554→			};
555→		} catch (error) {
556→			this.logger.error(
557→				`Error getting FBT v2 for style ${styleId}: ${(error as Error).message}`,
558→				(error as Error).stack,
559→			);
560→			throw error;
561→		}
562→	}
563→}
