439→	private calculateSeasonalComponent({
440→		values,
441→		period,
442→		harmonics,
443→	}: {
444→		values: number[];
445→		period: number;
446→		harmonics: number;
447→	}): number[] {
448→		const n = values.length;
449→		if (n < period) {
450→			return new Array(n).fill(0) as number[];
451→		}
452→
453→		try {
454→			const coefficients = MathematicalFunctions.fourierCoefficients({
455→				values,
456→				period,
457→				harmonics,
458→				precision: null,
459→			});
460→
461→			const seasonal = MathematicalFunctions.reconstructFourierSeries({
462→				period,
463→				harmonics,
464→				a: coefficients.a,
465→				b: coefficients.b,
466→				length: n,
467→			});
468→
469→			return seasonal;
470→		} catch (error) {
471→			this.logger.error(
472→				`Error extending seasonal component: ${(error as Error).message}`,
473→				(error as Error).stack,
474→			);
475→			return values.map((_, index) => {
476→				const cyclePosition = index % Math.max(1, Math.floor(period));
477→				const seasonalIndex = Math.min(cyclePosition, values.length - 1);
478→				return values[seasonalIndex] ? values[seasonalIndex] * 0.1 : 0;
479→			});
480→		}
481→	}
