483→	private calculateTrendComponent({
484→		values,
485→		changePoints,
486→		startDate,
487→		endDate,
488→	}: {
489→		values: number[];
490→		changePoints: number[];
491→		startDate: string;
492→		endDate: string;
493→	}): number[] {
494→		const n = values.length;
495→		if (n === 0) return [];
496→
497→		const dates = this.generateDateRange(startDate, endDate, n);
498→
499→		if (changePoints.length === 0) {
500→			return MathematicalFunctions.calculateTrend({ values, dates });
501→		}
502→
503→		const trend = new Array(n).fill(0) as number[];
504→		const segments = [0, ...changePoints, n];
505→
506→		for (let i = 0; i < segments.length - 1; i++) {
507→			const start = segments[i] as unknown as number;
508→			const end = segments[i + 1] as unknown as number;
509→			const segmentValues = values.slice(start, end);
510→			const segmentDates = dates.slice(start, end);
511→
512→			if (segmentValues.length > 1) {
513→				const segmentTrend = MathematicalFunctions.calculateTrend({
514→					values: segmentValues,
515→					dates: segmentDates,
516→				});
517→
518→				for (let j = 0; j < segmentTrend.length; j++) {
519→					trend[start + j] = segmentTrend[j] as unknown as number;
520→				}
521→			} else if (segmentValues.length === 1) {
522→				trend[start] = segmentValues[0] as unknown as number;
523→			}
524→		}
525→
526→		return trend;
527→	}
