529→	private generateDateRange(startDate: string, endDate: string, count: number): string[] {
530→		const start = new Date(startDate);
531→		const end = new Date(endDate);
532→		const totalDays =
533→			Math.floor((end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24)) + 1;
534→		const step = totalDays / count;
535→
536→		const dates: string[] = [];
537→		for (let i = 0; i < count; i++) {
538→			const currentDate = new Date(start.getTime() + i * step * 24 * 60 * 60 * 1000);
539→			const dateArr = currentDate.toISOString().split('T') as [string, string];
540→			dates.push(dateArr[0]);
541→		}
542→		return dates;
543→	}
