 60→	@LogExecution({
 61→		paramFormatter: (params) => params,
 62→		responseFormatter: () => '',
 63→	})
 64→	async get<T>({
 65→		namespace,
 66→		key,
 67→		consistency = ConsistencyLevel.EVENTUAL,
 68→	}: {
 69→		namespace: Namespaces;
 70→		key: string;
 71→		consistency?: ConsistencyLevel;
 72→	}): Promise<T | null> {
 73→		const namespacedKey = this.getNamespacedKey({ namespace, key });
 74→
 75→		const shouldReadFromMaster = this.shouldReadFromMaster({
 76→			key: namespacedKey,
 77→			consistency,
 78→		});
 79→		const cacheManager = shouldReadFromMaster
 80→			? this.cacheWriteManager
 81→			: this.cacheReadManager;
 82→		const source = shouldReadFromMaster ? 'master' : 'replica';
 83→
 84→		try {
 85→			const result = (await cacheManager.get(namespacedKey)) as T;
 86→
 87→			if (!result) {
 88→				this.logger.log('Cache miss', { namespace, key, consistency, source });
 89→				return null;
 90→			}
 91→
 92→			this.logger.log('Cache hit', { namespace, key });
 93→
 94→			return result;
 95→		} catch (error) {
 96→			const e = error as Error;
 97→			this.logger.error(`Error retrieving from cache: ${e.message}`, e.stack, { source });
 98→
 99→			if (!shouldReadFromMaster && this.isReadReplicaHealthy) {
100→				this.logger.warn('Read replica failed, falling back to master', {
101→					namespace,
102→					key,
103→				});
104→				this.isReadReplicaHealthy = false;
105→				return this.get({ namespace, key, consistency: ConsistencyLevel.STRONG });
106→			}
107→
108→			throw this.createCacheError({ code: 'CONNECTION_FAILED', originalError: e });
109→		}
110→	}
