192→	async searchProducts({
193→		query = '',
194→		filters = '',
195→		hitsPerPage = 20,
196→	}: {
197→		query?: string;
198→		filters?: string;
199→		hitsPerPage?: number;
200→	}): Promise<{ hits: AlgoliaRelatedProductHit[] }> {
201→		try {
202→			const suffixFilter = `index_suffix:"${ALGOLIA_OBJECT_ID_SUFFIXES[0]}"`;
203→			const combinedFilters = filters ? `(${filters}) AND ${suffixFilter}` : suffixFilter;
204→
205→			const searchResponse = await this.algoliaClient.search({
206→				requests: [
207→					{ indexName: this.indexName, query, filters: combinedFilters, hitsPerPage },
208→				],
209→			});
210→
211→			const firstResult = searchResponse.results[0];
212→			if (firstResult && 'hits' in firstResult) {
213→				return {
214→					hits: firstResult.hits as AlgoliaRelatedProductHit[],
215→				};
216→			}
217→
218→			return { hits: [] };
219→		} catch (error: unknown) {
220→			this.handleError({
221→				context: `Error searching products in Algolia with query "${query}" and filters "${filters}"`,
222→				error,
