 65→		paramFormatter: (params) => params,
 66→		responseFormatter: (response: AddonsCuratedResponseDto) => response.addons.length,
 67→	})
 68→	async getCuratedAddons(): Promise<AddonsCuratedResponseDto> {
 69→		try {
 70→			const cachedData = await this.cacheService.get<AddonsCuratedResponseDto>({
 71→				namespace: Namespaces.CURATED_ADDONS,
 72→				key: this.cacheKey,
 73→			});
 74→
 75→			if (cachedData) {
 76→				this.logger.log('Cache hit for curated addons', {
 77→					cacheKey: this.cacheKey,
 78→					count: cachedData.addons.length,
 79→				});
 80→				return { addons: shuffleArray({ array: cachedData.addons }) };
 81→			}
 82→
 83→			this.logger.log('Cache miss for curated addons', {
 84→				cacheKey: this.cacheKey,
 85→			});
 86→
 87→			const styleIds = this.curatedAddonsIds.map((id) => Number(id));
 88→
 89→			const stylesInStock = await this.stylesService.getStylesInStockByIds({
 90→				styleIds,
 91→			});
 92→
 93→			if (stylesInStock.length === 0) {
 94→				this.logger.warn('No curated addons products found in stock', {
 95→					requestedCount: this.curatedAddonsIds.length,
 96→				});
 97→				throw new NotFoundException('No curated addons products found in stock');
 98→			}
 99→
100→			const eligibleStyleIds = stylesInStock.map((style) => style.style_id);
101→
102→			const { products, mvRecords } =
103→				await this.productHydrationService.hydrateProductsWithColors({
104→					styleIds: eligibleStyleIds,
105→				});
106→			this.logger.log('[getCuratedAddons] Hydration complete', {
107→				hydratedCount: products.length,
108→			});
109→
110→			const addons = products.map((product) => {
111→				const mvRecord = mvRecords.get(product.style_id);
112→				const colors = this.productHydrationService.convertMvColorsToProductColors({
113→					colors: mvRecord?.colors ?? null,
114→				});
115→				return assignRandomColorToProduct({ product, availableColors: colors });
116→			});
117→
118→			const result = { addons };
119→
120→			await this.cacheService.set({
121→				namespace: Namespaces.CURATED_ADDONS,
122→				key: this.cacheKey,
123→				value: result,
124→				ttl: this.curatedAddonsCacheTtl,
125→			});
126→
127→			return { addons: shuffleArray({ array: result.addons }) };
128→		} catch (error) {
129→			if (error instanceof NotFoundException) {
130→				throw error;
131→			}
132→
133→			const err = error instanceof Error ? error : new Error(String(error));
134→			this.logger.error(`Error fetching curated addons: ${err.message}`, err.stack);
135→			throw err;
136→		}
137→	}
138→}
