323→	private async getFBTRecommendations({
324→		products,
325→	}: {
326→		products?: { productId: number; colorId?: number }[];
327→	}): Promise<IEmailRecommendationRawResult> {
328→		if (!products?.[0] || products.length === 0) {
329→			throw new BadRequestException('Products are required for FBT recommendations');
330→		}
331→
332→		this.logger.log('[getFBTRecommendations] Starting FBT fetch', {
333→			productIds: products.map((p) => p.productId),
334→		});
335→
336→		const productRecommendations = new Map<number, IRelatedProduct[]>();
337→		let fallbackUsed = false;
338→		let fallbackReason = '';
339→		const excludeIds = products.map((p) => p.productId);
340→
341→		try {
342→			const fbtResult =
343→				await this.frequentlyBoughtTogetherService.getFrequentlyBoughtTogether({
344→					styleIds: products.map((p) => p.productId),
345→					exclude: excludeIds,
346→				});
347→
348→			products.forEach((product) => {
349→				productRecommendations.set(
350→					product.productId,
351→					fbtResult.frequently_bought_together,
352→				);
353→			});
354→
355→			if (fbtResult.fallback_used) {
356→				fallbackUsed = true;
357→				fallbackReason = 'FBT service used fallback data';
358→			}
359→		} catch (error) {
360→			this.logger.warn(`FBT failed: ${error}`, {
361→				productIds: products.map((p) => p.productId),
362→			});
363→			products.forEach((product) => {
364→				productRecommendations.set(product.productId, []);
365→			});
366→			fallbackUsed = true;
367→			fallbackReason = 'FBT service failed';
368→		}
369→
370→		return {
371→			recommendations: productRecommendations,
372→			fallbackUsed,
373→			fallbackReason,
374→		};
375→	}
