403→				if (similarResult.mms_fallback && !fallbackUsed) {
404→					fallbackUsed = true;
405→					fallbackReason = 'Related products service used MMS fallback';
406→				}
407→			} catch (error) {
408→				this.logger.warn(`Similar recommendations failed: ${error}`, {
409→					productId: product.productId,
410→					colorId: product.colorId,
411→				});
412→				productRecommendations.set(product.productId, []);
413→				fallbackUsed = true;
414→				fallbackReason = 'Similar recommendations failed';
415→			}
416→		}
417→
418→		return {
419→			recommendations: productRecommendations,
420→			fallbackUsed,
421→			fallbackReason,
422→		};
