521→	private removeDuplicatesAndExcludeSource({
522→		products,
523→		excludeIds,
524→	}: {
525→		products: IRelatedProduct[];
526→		excludeIds: number[];
527→	}): IRelatedProduct[] {
528→		const seen = new Set<number>();
529→		return products.filter((product) => {
530→			if (seen.has(product.style_id)) {
531→				return false;
532→			}
533→			seen.add(product.style_id);
534→			return !excludeIds.includes(product.style_id);
535→		});
536→	}
537→
538→	private blendRecommendationsRoundRobin({
539→		productRecommendations,
540→	}: {
541→		productRecommendations: Map<number, IRelatedProduct[]>;
542→	}): IRelatedProduct[] {
543→		const blended: IRelatedProduct[] = [];
544→		const productIds = Array.from(productRecommendations.keys());
545→
546→		const maxLength = Math.max(
547→			...Array.from(productRecommendations.values()).map((arr) => arr.length),
548→		);
549→
550→		for (let i = 0; i < maxLength; i++) {
551→			for (const productId of productIds) {
552→				const recommendations = productRecommendations.get(productId);
553→				if (recommendations && i < recommendations.length) {
554→					const rec = recommendations[i];
555→					if (rec) {
556→						if (!blended.some((el) => el.style_id === rec.style_id)) {
557→							blended.push(rec);
558→						}
559→					}
560→				}
561→			}
562→		}
563→
564→		return blended;
565→	}
566→
567→	private blendRecommendationsByRating({
568→		productRecommendations,
569→	}: {
570→		productRecommendations: Map<number, IRelatedProduct[]>;
571→	}): IRelatedProduct[] {
572→		const allRecommendations: IRelatedProduct[] = [];
573→		const seen = new Set<number>();
574→
575→		for (const recommendations of productRecommendations.values()) {
576→			for (const rec of recommendations) {
577→				if (!seen.has(rec.style_id)) {
578→					seen.add(rec.style_id);
579→					allRecommendations.push(rec);
580→				}
581→			}
582→		}
583→
584→		return allRecommendations.sort((a, b) => {
585→			const ratingA =
586→				typeof a.rating_score === 'string'
587→					? parseFloat(a.rating_score) || 0
588→					: a.rating_score || 0;
589→			const ratingB =
590→				typeof b.rating_score === 'string'
591→					? parseFloat(b.rating_score) || 0
592→					: b.rating_score || 0;
593→
594→			return ratingB - ratingA;
595→		});
596→	}
597→
598→	private blendRecommendations({
599→		productRecommendations,
600→		strategy,
601→	}: {
602→		productRecommendations: Map<number, IRelatedProduct[]>;
603→		strategy: BlendStrategy;
604→	}): IRelatedProduct[] {
605→		switch (strategy) {
606→			case BlendStrategy.RATING:
607→				return this.blendRecommendationsByRating({ productRecommendations });
608→			case BlendStrategy.ROUND_ROBIN:
609→			default:
610→				return this.blendRecommendationsRoundRobin({ productRecommendations });
611→		}
612→	}
613→}
