296→				root_category_id: this.getRootCategoryId({ style, allCategories }),
297→				purchases_count: purchasesCount,
298→				categories_ids: categoryIds,
299→				categories_with_parents_ids: categoriesWithParentsIds,
300→				is_active: isProductActive,
301→				name: style.name,
302→				decoration_method: style.decoration_method,
303→				features: style.features,
